321: 	tokens, err := e.listTokenSecrets(serviceAccount)
322: 	if err != nil {
323: 		// don't retry on cache lookup errors
324: 		return false, err
325: 	}
326: 	retry := false
327: 	errs := []error{}
328: 	for _, token := range tokens {
329: 		r, err := e.deleteToken(token.Namespace, token.Name, token.UID)
